class Solution {
public:
    int bestClosingTime(string customers) {
        int n = customers.size();
        int curPenalty = 0;
        for (char c : customers) {
            if (c == 'Y') curPenalty++;
        }
        int minPenalty = curPenalty;
        int bestTime = n;
        for (int i = n - 1; i >= 0; --i) {
            if (customers[i] == 'Y') curPenalty--;
            else curPenalty++;
            if (curPenalty <= minPenalty) {
                minPenalty = curPenalty;
                bestTime = i;
            }
        }
        return bestTime;
    }
};
